"use client";

import { useEffect, useState, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

const faqs = [
  {
    question: "What do you mean by 'Open Source'?",
    answer: "Open source refers to a software development model in which the source code of a program is made freely available to the public, allowing anyone to view, modify, and distribute the code as they see fit.",
  },
  {
    question: "How do I make my first contribution to an open source project?",
    answer: "One common approach is to look for 'good first issue' or 'beginner-friendly' labels on open issues, which can provide a good entry point for new contributors. Feel free to contact us and we'll help you out as soon as we can.",
  },
  {
    question: "Can I contribute to an open source project even if I am not a developer?",
    answer: "Yes, open source projects often need help with documentation, testing, design, and other non-coding tasks. Check the project's documentation or contact the maintainers to see how you can contribute.",
  },
  {
    question: "What is the open source community?",
    answer: "The open source community is a group of individuals and organizations that collaborate on the development and maintenance of open source software. The community is typically characterized by a spirit of collaboration, transparency, and openness.",
  },
  {
    question: "What are some benefits of being part of the open source community?",
    answer: "The opportunity to collaborate with like-minded individuals, build your skills and experience in software development, and make meaningful contributions to important software projects. Join us now.",
  },
  {
    question: "How can I get involved in the open source community?",
    answer: "There are many ways to get involved in the open source community, including contributing to open source projects, attending events and conferences, participating in online forums and discussion groups, and joining open source communities on social media platforms.",
  },
  {
    question: "What are some ways to contribute to open source projects?",
    answer: "Some ways to contribute to open source projects include submitting bug reports, suggesting new features, creating documentation, writing code, improving existing code, providing feedback on issues, or helping with community management.",
  },
  {
    question: "What is a pull request in open source contribution?",
    answer: "A pull request is a proposed change to the codebase of an open source project that is submitted by a contributor for review and potential inclusion in the project.",
  },
];

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState<number | null>(null);
  const contentRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    gsap.registerPlugin(ScrollTrigger);

    if (typeof window === "undefined") return;

    gsap.utils.toArray(".faq-item").forEach((elem: any, i: number) => {
      gsap.fromTo(
        elem,
        { y: 30, opacity: 0 },
        {
          scrollTrigger: {
            trigger: elem,
            start: "top 90%",
          },
          duration: 0.6,
          y: 0,
          opacity: 1,
          ease: "power2.out",
          delay: i * 0.05,
        }
      );
    });

    return () => {
      ScrollTrigger.getAll().forEach((st) => st.kill());
    };
  }, []);

  const toggleFAQ = (index: number) => {
    if (openIndex === index) {
      setOpenIndex(null);
    } else {
      setOpenIndex(index);
    }
  };

  useEffect(() => {
    contentRefs.current.forEach((el, idx) => {
      if (el) {
        if (openIndex === idx) {
          gsap.to(el, { height: "auto", opacity: 1, duration: 0.3, ease: "power2.out" });
        } else {
          gsap.to(el, { height: 0, opacity: 0, duration: 0.3, ease: "power2.out" });
        }
      }
    });
  }, [openIndex]);

  return (
    <>
      <section
        className="page-header"
        style={{ paddingTop: "200px", paddingBottom: "80px", textAlign: "center" }}
      >
        <div className="badge-wrapper">
          <span className="badge">Support & Info</span>
        </div>
        <h1
          className="page-title"
          style={{
            fontSize: "clamp(3rem, 6vw, 4.5rem)",
            textTransform: "uppercase",
            marginBottom: "1rem",
          }}
        >
          Frequently Asked <span className="italic-serif highlight-yellow">Questions</span>
        </h1>
        <p
          style={{
            color: "var(--c-text-muted)",
            fontSize: "1.25rem",
            maxWidth: "700px",
            margin: "0 auto",
          }}
        >
          Find answers to common questions about open source and getting started with contributions.
        </p>
      </section>

      <section
        className="faq-container"
        style={{
          maxWidth: "800px",
          margin: "0 auto 150px auto",
          padding: "0 2rem",
        }}
      >
        {faqs.map((faq, index) => (
          <div
            key={index}
            className="faq-item"
            style={{
              marginBottom: "1rem",
              background: "var(--c-dark-sec)",
              border: "1px solid rgba(0, 255, 102, 0.1)",
              borderRadius: "12px",
              overflow: "hidden",
            }}
          >
            <button
              onClick={() => toggleFAQ(index)}
              style={{
                width: "100%",
                padding: "1.5rem 2rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                background: "transparent",
                border: "none",
                color: "var(--c-light)",
                fontSize: "1.1rem",
                fontWeight: 600,
                textAlign: "left",
                cursor: "pointer",
              }}
            >
              {faq.question}
              <span
                style={{
                  display: "inline-block",
                  transition: "transform 0.3s ease",
                  transform: openIndex === index ? "rotate(180deg)" : "rotate(0deg)",
                  color: "var(--c-primary)",
                  fontSize: "1.5rem",
                }}
              >
                Γåô
              </span>
            </button>
            <div
              ref={(el) => {
                contentRefs.current[index] = el;
              }}
              style={{
                height: 0,
                opacity: 0,
                overflow: "hidden",
              }}
            >
              <div
                style={{
                  padding: "0 2rem 1.5rem 2rem",
                  color: "var(--c-text-muted)",
                  lineHeight: 1.6,
                }}
              >
                {faq.answer}
              </div>
            </div>
          </div>
        ))}
      </section>
    </>
  );
}

"use client";

import { useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

export default function Handbook() {
  useEffect(() => {
    gsap.registerPlugin(ScrollTrigger);

    if (typeof window === "undefined") return;

    // Simple reveal animation for handbook sections
    gsap.utils.toArray(".handbook-section").forEach((elem: any) => {
      gsap.fromTo(
        elem,
        { y: 30, opacity: 0 },
        {
          scrollTrigger: {
            trigger: elem,
            start: "top 85%",
          },
          duration: 0.8,
          y: 0,
          opacity: 1,
          ease: "power2.out",
        }
      );
    });

    return () => {
      ScrollTrigger.getAll().forEach((st) => st.kill());
    };
  }, []);

  return (
    <>
      <section
        className="page-header"
        style={{ paddingTop: "200px", paddingBottom: "100px", textAlign: "center" }}
      >
        <div className="badge-wrapper">
          <span className="badge">Guidelines</span>
        </div>
        <h1
          className="page-title"
          style={{
            fontSize: "clamp(3rem, 6vw, 5rem)",
            textTransform: "uppercase",
            marginBottom: "1rem",
          }}
        >
          Community <span className="italic-serif highlight-yellow">Handbook</span>
        </h1>
      </section>

      <section
        className="handbook-content"
        style={{
          maxWidth: "800px",
          margin: "0 auto 100px auto",
          background: "var(--c-dark-sec)",
          border: "1px solid rgba(0, 255, 102, 0.2)",
          borderRadius: "12px",
          padding: "3rem",
        }}
      >
        <div
          className="handbook-section"
          style={{
            marginBottom: "3rem",
            borderBottom: "1px dashed rgba(255, 255, 255, 0.1)",
            paddingBottom: "2rem",
          }}
        >
          <h2
            style={{
              display: "flex",
              alignItems: "center",
              gap: "1rem",
              color: "var(--c-light)",
              fontFamily: "var(--f-serif)",
              marginBottom: "1rem",
            }}
          >
            <svg
              className="handbook-icon"
              width="28"
              height="28"
              viewBox="0 0 24 24"
              fill="none"
              stroke="var(--c-primary)"
              strokeWidth="2"
            >
              <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path>
              <polyline points="22 4 12 14.01 9 11.01"></polyline>
            </svg>
            Code of Conduct
          </h2>
          <p
            style={{
              color: "var(--c-text-muted)",
              lineHeight: 1.8,
              marginBottom: "1rem",
            }}
          >
            We are committed to providing a friendly, safe, and welcoming environment
            for all, regardless of gender, sexual orientation, ability, ethnicity,
            socioeconomic status, or religion.
          </p>
          <a
            href="https://docs.fosscu.org/docs/code-of-conduct"
            className="btn btn-outline"
            style={{ fontSize: "0.8rem", padding: "0.5rem 1rem" }}
            target="_blank"
            rel="noreferrer"
          >
            Read Full CoC
          </a>
        </div>

        <div
          className="handbook-section"
          style={{
            marginBottom: "3rem",
            borderBottom: "1px dashed rgba(255, 255, 255, 0.1)",
            paddingBottom: "2rem",
          }}
        >
          <h2
            style={{
              display: "flex",
              alignItems: "center",
              gap: "1rem",
              color: "var(--c-light)",
              fontFamily: "var(--f-serif)",
              marginBottom: "1rem",
            }}
          >
            <svg
              className="handbook-icon"
              width="28"
              height="28"
              viewBox="0 0 24 24"
              fill="none"
              stroke="var(--c-primary)"
              strokeWidth="2"
            >
              <circle cx="12" cy="12" r="10"></circle>
              <polyline points="12 6 12 12 16 14"></polyline>
            </svg>
            Contribution Guidelines
          </h2>
          <p
            style={{
              color: "var(--c-text-muted)",
              lineHeight: 1.8,
              marginBottom: "1rem",
            }}
          >
            Contributions are the lifeblood of our operation. Whether you're fixing a
            typo, adding a feature to Wand, or organizing an event, your effort
            matters.
          </p>
          <p
            style={{
              color: "var(--c-text-muted)",
              lineHeight: 1.8,
              marginBottom: "1rem",
            }}
          >
            Please review our standard pull request workflow and issue templates
            before submitting code.
          </p>
        </div>

        <div
          className="handbook-section"
          style={{ marginBottom: 0, paddingBottom: 0, borderBottom: "none" }}
        >
          <h2
            style={{
              display: "flex",
              alignItems: "center",
              gap: "1rem",
              color: "var(--c-light)",
              fontFamily: "var(--f-serif)",
              marginBottom: "1rem",
            }}
          >
            <svg
              className="handbook-icon"
              width="28"
              height="28"
              viewBox="0 0 24 24"
              fill="none"
              stroke="var(--c-primary)"
              strokeWidth="2"
            >
              <path d="M12 2A10 10 0 0 0 2 12c0 4.42 2.87 8.17 6.84 9.5c.5.08.66-.23.66-.5v-1.69c-2.77.6-3.36-1.34-3.36-1.34c-.46-1.16-1.11-1.47-1.11-1.47c-.91-.62.07-.6.07-.6c1 .07 1.53 1.03 1.53 1.03c.87 1.52 2.34 1.07 2.91.83c.09-.65.35-1.09.63-1.34c-2.22-.25-4.55-1.11-4.55-4.92c0-1.11.38-2 1.03-2.71c-.1-.25-.45-1.29.1-2.64c0 0 .84-.27 2.75 1.02c.79-.22 1.65-.33 2.5-.33c.85 0 1.71.11 2.5.33c1.91-1.29 2.75-1.02 2.75-1.02c.55 1.35.2 2.39.1 2.64c.65.71 1.03 1.6 1.03 2.71c0 3.82-2.34 4.66-4.57 4.91c.36.31.69.92.69 1.85V21c0 .27.16.59.67.5C19.14 20.16 22 16.42 22 12A10 10 0 0 0 12 2Z"></path>
            </svg>
            Repository Standards
          </h2>
          <p
            style={{
              color: "var(--c-text-muted)",
              lineHeight: 1.8,
              marginBottom: "1rem",
            }}
          >
            All FOSSCU repositories must contain a README, a LICENSE (preferably MIT
            or GPL), and a contributing guide.
          </p>
        </div>
      </section>
    </>
  );
}

import type { Metadata } from "next";
import "./globals.css";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import Cursor from "@/components/Cursor";

export const metadata: Metadata = {
  title: "FOSSCU | Empowering Open Source",
  description: "FOSSCU - Free and Open-Source Software Community United. Join the talent layer of open source.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <head>
        {/* Fonts */}
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="anonymous" />
        <link
          href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Space+Grotesk:wght@500;700&display=swap"
          rel="stylesheet"
        />
      </head>
      <body>
        <Cursor />
        <Navbar />
        <main>{children}</main>
        <Footer />
      </body>
    </html>
  );
}
